mapper.update:
update store
   set order_count = (select count(*) from orders where store_id = #{storeId})
 where store_id = #{storeId}

mapper.select:
SELECT COALESCE(SUM(od.menu_price * od.quantity), 0)
FROM orders o
         JOIN order_detail od ON od.order_id = o.order_id
WHERE o.store_id = #{storeId}
  AND o.order_time >= #{start}
  AND o.order_time < #{end}
  AND o.order_state != 2
